SELECT experiment_id
FROM experiments
WHERE project_id = (SELECT project_id FROM projects ORDER BY updated_at DESC LIMIT 1);

SELECT hidden_dim 
FROM experiment_configs 
WHERE experiment_id = 1;

SELECT COUNT(*) 
FROM experiment_tags 
WHERE tag = 'baseline model';

SELECT COUNT(DISTINCT experiment_id) 
FROM experiments 
WHERE project_id = 1;
